/**
 * MedFind Universal Logo Component v1.0
 * Injects consistent logo across all pages
 * Usage: <script src="../../assets/js/logo.js"></script>
 *        Then add class="mf-logo" to nav brand img tags
 */
(function() {
  const LOGO_SRC = 'data:image/png;base64,';
  
  // Replace all logo placeholders
  document.addEventListener('DOMContentLoaded', function() {
    // Replace all nav brand images
    document.querySelectorAll('.mf-logo-img').forEach(function(img) {
      img.src = LOGO_SRC;
      img.alt = 'MedFind Bangladesh';
    });
    // Replace text-only logos with image
    document.querySelectorAll('.mf-logo-text').forEach(function(el) {
      const img = document.createElement('img');
      img.src = LOGO_SRC;
      img.alt = 'MedFind';
      img.style.cssText = 'height:40px;width:auto;object-fit:contain;';
      el.parentNode.replaceChild(img, el);
    });
  });
})();
